ee:message.ee:set-payload:
%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
var row = vars.existing[0]
---
{
  soap#Envelope: {
    soap#Body: {
      cer#generateCertificateResponse: {
        cer#certificateId:       row.certificate_id,
        cer#studentId:           row.student_id,
        cer#courseId:            row.course_id,
        cer#status:              row.status,
        cer#issueDate:           row.issue_date as String { format: "yyyy-MM-dd" },
        cer#repositoryReference: row.repository_reference,
        cer#message:             "Certificate already generated (idempotent response)"
      }
    }
  }
}

%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
---
{
  soap#Envelope: {
    soap#Body: {
      cer#generateCertificateResponse: {
        cer#studentId: vars.req.studentId,
        cer#courseId:  vars.req.courseId,
        cer#status:    "NOT_ELIGIBLE",
        cer#message:   "Final grade " ++ (vars.req.finalGrade as String)
                        ++ " is below the minimum required ("
                        ++ 5.0 ++ ")"
      }
    }
  }
}

ee:variables.ee:set-variable:
%dw 2.0
output application/java
import * from dw::Runtime
import * from dw::core::Strings
var uuid = uuid()
---
{
  certificateId:       uuid,
  repositoryReference: ("REPO-CERT-")
                       ++ (uuid[0 to 7]),
  issueDate:           now() as String { format: "yyyy-MM-dd" }
}

ee:message.ee:set-payload:
%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
---
{
  soap#Envelope: {
    soap#Body: {
      cer#generateCertificateResponse: {
        cer#certificateId:       vars.newCert.certificateId,
        cer#studentId:           vars.req.studentId,
        cer#courseId:            vars.req.courseId,
        cer#status:              "GENERATED",
        cer#issueDate:           vars.newCert.issueDate,
        cer#repositoryReference: vars.newCert.repositoryReference,
        cer#message:             "Certificate issued successfully"
      }
    }
  }
}

%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
var row = payload[0]
---
{
  soap#Envelope: {
    soap#Body: {
      cer#getCertificateResponse: {
        cer#certificateId:       row.certificate_id,
        cer#studentId:           row.student_id,
        cer#courseId:            row.course_id,
        cer#finalGrade:          row.final_grade,
        cer#completionDate:      row.completion_date as String { format: "yyyy-MM-dd" },
        cer#issueDate:           row.issue_date as String { format: "yyyy-MM-dd" },
        cer#status:              row.status,
        cer#repositoryReference: row.repository_reference
      }
    }
  }
}

%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
---
{
  soap#Envelope: {
    soap#Body: {
      soap#Fault: {
        faultcode:   "soap:Client",
        faultstring: "Unsupported SOAP operation",
        detail: {
          cer#ServiceFault: {
            cer#code:    "UNSUPPORTED_OPERATION",
            cer#message: "SOAPAction not recognised: " ++ (vars.soapAction default "<missing>"),
            cer#detail:  "Allowed: generateCertificate, getCertificate"
          }
        }
      }
    }
  }
}

%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
---
{
  soap#Envelope: {
    soap#Body: {
      soap#Fault: {
        faultcode:   "soap:Client",
        faultstring: vars.faultMessage default "Business error",
        detail: {
          cer#ServiceFault: {
            cer#code:    vars.faultCode default "BUSINESS_ERROR",
            cer#message: vars.faultMessage default "Business error",
            cer#detail:  vars.faultDetail default ""
          }
        }
      }
    }
  }
}

%dw 2.0
output application/xml
ns soap http://schemas.xmlsoap.org/soap/envelope/
ns cer http://mtis.ua.es/elearning/certificates
---
{
  soap#Envelope: {
    soap#Body: {
      soap#Fault: {
        faultcode:   "soap:Server",
        faultstring: "Internal Server Error",
        detail: {
          cer#ServiceFault: {
            cer#code:    "INTERNAL_ERROR",
            cer#message: (error.description default "Unexpected error"),
            cer#detail:  (error.errorType.identifier default "")
          }
        }
      }
    }
  }
}
